\begin{definition}\label{ref:secantLocus:def}    
    Let $T\colon \LL\into \tconcspacecurly$ be a concise tensor on $X$, where every $\WW_i$ has rank $m$.
    \begin{enumerate}
        \item The \emph{minimal border rank locus} is the smallest closed
            subscheme $X^{\brk=m} \subseteq X$ such that for every $x\in
            X^{\brk=m}$, the tensor $T|_x$ has border rank $m$.
        \item The \emph{minimal border cactus rank locus} is the smallest closed
            subscheme $X^{\bcrk=m} \subseteq X$ such that for every $x\in
            X^{\bcrk=m}$, the tensor $T|_x$ has cactus rank $m$, assuming the underlying scheme is reduced.
    \end{enumerate}
    We say that $T$ \emph{has minimal border rank} if the respective locus is equal to $X$.
\end{definition}

\begin{definition}[Concise secant and cactus varieties]\label{ref:conciseSecant:def}
    Let $V_1, \ldots ,V_d$ be vector spaces over a field $K$ of characteristic two. Fix an integer $m\geq 1$.
    \begin{enumerate}
        \item
            \emph{The $m$-th concise secant variety} $\csigma_m$ is the minimal border rank locus
            for the universal tensor on the unrestriction scheme $\pi\colon \unrespar{}{\Tproj}\to \mathbb{P}(\tspace)$.
            The map $\rho\colon \csigma_m \onto \sigma_m$ is always birational.
    \end{enumerate}
\end{definition}

